+            return false;
+        };
+
+        if *blink_speed <= 0.0 {
+            // No blinking, always visible
+            return true;
+        }
+
+        // Blink cycle: on for half, off for half
+        let cycle = self.time * blink_speed;
+        (cycle % 1.0) < 0.5
+    }
