+    /// Handle step advancement and looping logic.
+    fn advance_step(&mut self) -> Option<SequenceEvent> {
+        let is_last_step = if self.forward {
+            self.current_step >= self.steps.len() - 1
+        } else {
+            self.current_step == 0
+        };
+
+        if is_last_step {
